          role="button"
          tabIndex={0}
          className={cls}
          onClick={() => onClick?.(id)}
          onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); onClick?.(id); } }}
          onMouseEnter={() => setHovered(true)}
